#include<bits/stdc++.h>
using namespace std;
const long long nulltag=114514;
long long b[100010];
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long sum0,sum1,lmax0,rmax0,lmax1,rmax1,ans0,ans1;
        long long rev_tag,upd_tag;
    }t[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(node &x,node ls,node rs)
    {
        bool flagl0=(ls.sum0==(ls.r-ls.l+1)),flagr0=(rs.sum0==(rs.r-rs.l+1));
        bool flagl1=(ls.sum1==(ls.r-ls.l+1)),flagr1=(rs.sum1==(rs.r-rs.l+1));
        x.sum0=ls.sum0+rs.sum0;
        x.lmax0=ls.lmax0;
        if(flagl0)
        {
            x.lmax0=ls.sum0+rs.lmax0;
        }
        x.rmax0=rs.rmax0;
        if(flagr0)
        {
            x.rmax0=rs.sum0+ls.rmax0;
        }
        x.ans0=max({ls.ans0,rs.ans0,ls.rmax0+rs.lmax0});
        x.sum1=ls.sum1+rs.sum1;
        x.lmax1=ls.lmax1;
        if(flagl1)
        {
            x.lmax1=ls.sum1+rs.lmax1;
        }
        x.rmax1=rs.rmax1;
        if(flagr1)
        {
            x.rmax1=rs.sum1+ls.rmax1;
        }
        x.ans1=max({ls.ans1,rs.ans1,ls.rmax1+rs.lmax1});
    }
    void pushupd(long long x,long long v)
    {
        if(v==nulltag)
        {
            return;
        }
        t[x].sum0=t[x].lmax0=t[x].rmax0=t[x].ans0=(1-v)*(t[x].r-t[x].l+1);
        t[x].sum1=t[x].lmax1=t[x].rmax1=t[x].ans1=v*(t[x].r-t[x].l+1);
        t[x].upd_tag=v;
    }
    void pushrev(long long x)
    {
        swap(t[x].sum0,t[x].sum1);
        swap(t[x].lmax0,t[x].lmax1);
        swap(t[x].rmax0,t[x].rmax1);
        swap(t[x].ans0,t[x].ans1);
        if(t[x].upd_tag!=nulltag)
        {
            t[x].upd_tag^=1;
        }
        t[x].rev_tag^=1;
    }
    void pushup(long long x)
    {
        pushup(t[x],t[t[x].lson],t[t[x].rson]);
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        t[x].l=l;
        t[x].r=r;
        t[x].upd_tag=nulltag;
        t[x].rev_tag=0;
        if(l==r)
        {
            t[x].sum0=t[x].lmax0=t[x].rmax0=t[x].ans0=(1-b[l]);
            t[x].sum1=t[x].lmax1=t[x].rmax1=t[x].ans1=b[l];
            return x;
        }
        long long mid=(l+r)>>1;
        t[x].lson=init(l,mid);
        t[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void pushdown(long long x)
    {
        if(t[x].rev_tag)
        {
            pushrev(t[x].lson);
            pushrev(t[x].rson);
            t[x].rev_tag=0;
        }
        if(t[x].upd_tag!=nulltag)
        {
            pushupd(t[x].lson,t[x].upd_tag);
            pushupd(t[x].rson,t[x].upd_tag);
            t[x].upd_tag=nulltag;
        }
    }
    void update(long long x,long long l,long long r,long long v)
    {
        if(t[x].l>r||t[x].r<l)
        {
            return;
        }
        if(l<=t[x].l&&t[x].r<=r)
        {
            pushupd(x,v);
            return;
        }
        pushdown(x);
        update(t[x].lson,l,r,v);
        update(t[x].rson,l,r,v);
        pushup(x);
    }
    void reverse(long long x,long long l,long long r)
    {
        if(t[x].l>r||t[x].r<l)
        {
            return;
        }
        if(l<=t[x].l&&t[x].r<=r)
        {
            pushrev(x);
            return;
        }
        pushdown(x);
        reverse(t[x].lson,l,r);
        reverse(t[x].rson,l,r);
        pushup(x);
    }
    node query(long long x,long long l,long long r)
    {
        pushdown(x);
        if(l<=t[x].l&&t[x].r<=r)
        {
            return t[x];
        }
        long long mid=(t[x].l+t[x].r)>>1;
        if(l<=mid&&r>mid)
        {
            node ans=t[x];
            pushup(ans,query(t[x].lson,l,r),query(t[x].rson,l,r));
            return ans;
        }
        else if(l<=mid)
        {
            return query(t[x].lson,l,r);
        }
        else
        {
            return query(t[x].rson,l,r);
        }
    }
}t;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    t.init(1,n);
    while(m--)
    {
        long long op,x,y;
        scanf("%lld%lld%lld",&op,&x,&y);
        x++;
        y++;
        if(op==0)
        {
            t.update(1,x,y,0);
        }
        else if(op==1)
        {
            t.update(1,x,y,1);
        }
        else if(op==2)
        {
            t.reverse(1,x,y);
        }
        else if(op==3)
        {
            printf("%lld\n",t.query(1,x,y).sum1);
        }
        else
        {
            printf("%lld\n",t.query(1,x,y).ans1);
        }
    }
    return 0;
}
